import{_ as i,o as t,c as g,a0 as h}from"./chunks/framework.jwovEGr5.js";const p=JSON.parse('{"title":"Định giá","description":"","frontmatter":{"title":"Định giá"},"headers":[],"relativePath":"pricing.md","filePath":"pricing.md"}'),c={name:"pricing.md"};function o(a,n,r,l,s,u){return t(),g("div",null,[...n[0]||(n[0]=[h('<h1 id="đinh-gia" tabindex="-1">Định giá <a class="header-anchor" href="#đinh-gia" aria-label="Permalink to &quot;Định giá&quot;">​</a></h1><p>Mô-đun <strong>Định giá (Pricing)</strong> trong ABNERP cung cấp bộ công cụ linh hoạt để thiết lập và quản lý giá bán cho các mặt hàng và dịch vụ. Mô-đun này hỗ trợ nhiều chiến lược định giá khác nhau, từ bảng giá cố định đến quy tắc định giá tự động dựa trên nhiều tiêu chí.</p><h2 id="quy-tac-đinh-gia" tabindex="-1">Quy tắc định giá <a class="header-anchor" href="#quy-tac-đinh-gia" aria-label="Permalink to &quot;Quy tắc định giá&quot;">​</a></h2><p><strong>Quy tắc định giá (Pricing Rule)</strong> cho phép doanh nghiệp tự động tính toán giá bán dựa trên các điều kiện cụ thể. Quy tắc định giá có thể được thiết lập theo:</p><ul><li><strong>Khách hàng</strong>: giá đặc biệt cho khách hàng VIP hoặc nhóm khách hàng</li><li><strong>Loại khách hàng</strong>: giá sỉ, giá lẻ, giá đại lý</li><li><strong>Số lượng</strong>: chiết khấu theo số lượng mua (ví dụ: mua 10 sản phẩm giảm 5%)</li><li><strong>Ngày tháng</strong>: giá khuyến mãi theo mùa, chương trình ưu đãi đặc biệt</li><li><strong>Khu vực</strong>: giá theo từng khu vực địa lý khác nhau</li><li><strong>Loại mặt hàng</strong>: áp dụng cho nhóm hàng hóa cụ thể</li></ul><p>Mỗi quy tắc có thể áp dụng một mức chiết khấu (theo % hoặc số tiền) hoặc ghi đè giá trực tiếp. Hệ thống cho phép tạo nhiều quy tắc và sắp xếp thứ tự ưu tiên áp dụng.</p><h2 id="bang-gia" tabindex="-1">Bảng giá <a class="header-anchor" href="#bang-gia" aria-label="Permalink to &quot;Bảng giá&quot;">​</a></h2><p><strong>Bảng giá (Price List)</strong> là tập hợp các mức giá cho nhiều mặt hàng. ABNERP cho phép tạo không giới hạn bảng giá, phục vụ các mục đích khác nhau:</p><ul><li><strong>Bảng giá bán chuẩn</strong>: giá niêm yết chính thức</li><li><strong>Bảng giá sỉ</strong>: giá cho khách mua sỉ</li><li><strong>Bảng giá đại lý</strong>: giá cho đối tác đại lý</li><li><strong>Bảng giá khuyến mãi</strong>: giá ưu đãi có thời hạn</li><li><strong>Bảng giá mua</strong>: giá nhập hàng từ nhà cung cấp</li></ul><p>Mỗi bảng giá có thể được đánh dấu là mặc định (chuẩn) và được gắn với một loại tiền tệ cụ thể. Người dùng có thể dễ dàng chuyển đổi và sao chép giữa các bảng giá.</p><h2 id="gia-mat-hang" tabindex="-1">Giá mặt hàng <a class="header-anchor" href="#gia-mat-hang" aria-label="Permalink to &quot;Giá mặt hàng&quot;">​</a></h2><p><strong>Giá mặt hàng (Item Price)</strong> là giá cụ thể của một mặt hàng trong một bảng giá nhất định. Khi tạo giá mặt hàng, người dùng có thể cấu hình:</p><ul><li><strong>Mặt hàng</strong>: sản phẩm hoặc dịch vụ cần định giá</li><li><strong>Nhà cung cấp</strong>: giá nhập từ một nhà cung cấp cụ thể (dùng cho bảng giá mua)</li><li><strong>Đơn vị tính</strong>: giá có thể khác nhau cho các đơn vị tính khác nhau (cái/thùng/hộp)</li><li><strong>UOM (Đơn vị đo lường)</strong>: giá theo từng đơn vị</li><li><strong>Số lượng tối thiểu</strong>: giá này áp dụng khi mua từ mức số lượng tối thiểu trở lên</li><li><strong>Ngày hiệu lực</strong>: ngày bắt đầu và ngày kết thúc áp dụng giá</li></ul><p>Hệ thống tự động ưu tiên giá dựa trên bảng giá được chọn trong chứng từ bán hàng hoặc mua hàng, đảm bảo nhân viên luôn sử dụng đúng giá cho từng đối tượng khách hàng.</p>',14)])])}const m=i(c,[["render",o]]);export{p as __pageData,m as default};
